1	import { WebSocketServer } from 'ws';
2	
3	// WebSocket.OPEN = 1 — use numeric constant to avoid importing the WebSocket class
4	const WS_OPEN = 1;
5	
6	let wss = null;
7	let clients = new Set();
8	let heartbeatInterval = null;
9	
10	function initWs(httpServer, { pingInterval = 30000 } = {}) {
11	  // Defensive: clear any existing state from a previous call without closeWs
12	  if (heartbeatInterval) {
13	    clearInterval(heartbeatInterval);
14	    heartbeatInterval = null;
15	  }
16	  clients = new Set();
17	
18	  wss = new WebSocketServer({ server: httpServer });
19	
20	  wss.on('connection', (ws) => {
21	    ws.isAlive = true;
22	    clients.add(ws);
23	
24	    ws.on('pong', () => { ws.isAlive = true; });
25	    ws.on('close', () => { clients.delete(ws); });
26	    ws.on('error', () => { clients.delete(ws); });
27	  });
28	
29	  heartbeatInterval = setInterval(() => {
30	    for (const client of clients) {
31	      if (!client.isAlive) {
32	        clients.delete(client);
33	        client.terminate();
34	      } else {
35	        client.isAlive = false;
36	        client.ping();
37	      }
38	    }
39	  }, pingInterval);
40	
41	  wss.on('close', () => {
42	    clearInterval(heartbeatInterval);
43	    heartbeatInterval = null;
44	  });
45	}
46	
47	function broadcast(event, payload) {
48	  const data = JSON.stringify({ event, payload });
49	  for (const client of clients) {
50	    if (client.readyState === WS_OPEN) {
51	      try {
52	        client.send(data);
53	      } catch {
54	        // Isolate per-client send errors; do not crash the broadcaster
55	      }
56	    }
57	  }
58	}
59	
60	// closeWs: exported for test teardown; terminates all open connections so
61	// wss.close() does not hang waiting for them to close naturally.
62	async function closeWs() {
63	  clearInterval(heartbeatInterval);
64	  heartbeatInterval = null;
65	  for (const client of clients) {
66	    client.terminate();
67	  }
68	  clients = new Set();
69	  if (wss) {
70	    await new Promise((resolve) => wss.close(resolve));
71	    wss = null;
72	  }
73	}
74	
75	export { initWs, broadcast, closeWs };
