7	router.post('/cards/:id/comments', (req, res, next) => {
8	  const { author, content } = req.body ?? {};
9	
10	  if (!author || !content) {
11	    return res.status(400).json({ error: 'author and content are required' });
12	  }
13	
14	  try {
15	    const comment = createComment(req.params.id, { author, content });
16	    try { broadcast('comment:created', comment); } catch { /* isolate broadcast errors */ }
17	    return res.status(201).json(comment);
18	  } catch (err) {
19	    if (err instanceof ForeignKeyError) {
20	      return res.status(404).json({ error: err.message });
21	    }
22	    next(err); // passes to Express error handler → 500
23	  }
24	});
25	
26	export default router;
